// src/settings.ts
var import_obsidian = require("obsidian");
var DEFAULT_SETTINGS = {
  palette: "nord",
  theme: "auto"
};
var DgmoSettingTab = class extends import_obsidian.PluginSettingTab {
  constructor(app, plugin) {
    super(app, plugin);
    this.plugin = plugin;
  }
  display() {
    const { containerEl } = this;
    containerEl.empty();
    const aboutEl = containerEl.createDiv({ cls: "dgmo-settings-about" });
    const introEl = aboutEl.createEl("p", { cls: "setting-item-description" });
    introEl.appendText(
      "Diagrammo turns plain-text markup into beautiful charts and diagrams \u2014 bar, line, pie, sequence, arc, timeline, and more. Just write a "
    );
    introEl.createEl("code", { text: "```dgmo" });
    introEl.appendText(" code fence and it renders inline in your notes.");
    const linksEl = aboutEl.createEl("p", { cls: "setting-item-description" });
    linksEl.createEl("a", {
      text: "Diagrammo.app",
      href: "https://diagrammo.app"
    });
    linksEl.appendText(
      " \u2014 A dedicated desktop editor with live preview, export to PNG/SVG, and all the palettes and chart types in one place. Great for when you want to go beyond what a code fence can do."
    );
    const cliEl = aboutEl.createEl("p", { cls: "setting-item-description" });
    cliEl.appendText("You can also use dgmo from the terminal: ");
    cliEl.createEl("a", {
      text: "Homebrew tap",
      href: "https://github.com/diagrammo/homebrew-dgmo"
    });
    cliEl.appendText(" or ");
    cliEl.createEl("a", {
      text: "npm install @diagrammo/dgmo",
      href: "https://www.npmjs.com/package/@diagrammo/dgmo"
    });
    cliEl.appendText(".");
    const palettes = getAvailablePalettes();
    new import_obsidian.Setting(containerEl).setName("Palette").setDesc("Color palette used for all dgmo diagrams.").addDropdown((dropdown) => {
      for (const p2 of palettes) {
        dropdown.addOption(p2.id, p2.name);
      }
      dropdown.setValue(this.plugin.settings.palette);
      dropdown.onChange(async (value) => {
        this.plugin.settings.palette = value;
        await this.plugin.saveSettings();
      });
    });
    new import_obsidian.Setting(containerEl).setName("Theme").setDesc("Auto follows Obsidian's light/dark mode. Override to force one.").addDropdown((dropdown) => {
      dropdown.addOption("auto", "Auto (follow Obsidian)");
      dropdown.addOption("light", "Light");
      dropdown.addOption("dark", "Dark");
      dropdown.setValue(this.plugin.settings.theme);
      dropdown.onChange(async (value) => {
        this.plugin.settings.theme = value;
        await this.plugin.saveSettings();
      });
    });
  }
};

// src/main.ts
var DgmoPlugin = class extends import_obsidian2.Plugin {
  constructor() {
    super(...arguments);
    this.settings = DEFAULT_SETTINGS;
  }
  async onload() {
    await this.loadSettings();
    this.addSettingTab(new DgmoSettingTab(this.app, this));
    this.registerMarkdownCodeBlockProcessor("dgmo", async (source, el) => {
      await ensureInterFonts();
      const isDark = this.resolveIsDark();
      await renderDgmo(source, el, isDark, this.settings.palette);
    });
    this.addCommand({
      id: "insert-example-note",
      name: "Create example note with all chart types",
      callback: () => this.createExampleNote()
    });
  }
  async createExampleNote() {
    const path2 = "Diagrammo Examples.md";
    const existing = this.app.vault.getAbstractFileByPath(path2);
    if (existing) {
      new import_obsidian2.Notice(`"${path2}" already exists \u2014 open it or delete it first.`);
      return;
    }
    const file = await this.app.vault.create(path2, EXAMPLE_NOTE);
    await this.app.workspace.getLeaf().openFile(file);
    new import_obsidian2.Notice("Diagrammo examples note created.");
  }
  async loadSettings() {
    this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
  }
  async saveSettings() {
    await this.saveData(this.settings);
  }
  resolveIsDark() {
    if (this.settings.theme === "light") return false;
    if (this.settings.theme === "dark") return true;
    return document.body.classList.contains("theme-dark");
  }
};
